    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel
        using var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("should not reach"),
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/data", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        // Arrange
        using var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast response"),
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act — pass TestContext.CancellationToken so [Timeout] can cancel the test
        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("fast response", result);
    }

    [TestMethod]
    [Timeout(500)]
    public async Task FetchAsync_SlowResponse_TimeoutCancelsViaTestContext()
    {
        // Arrange — handler delays longer than the [Timeout]
        using var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("too slow"),
            },
            simulatedDelay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — [Timeout] fires CancellationToken, causing TaskCanceledException
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/slow", _testContext.CancellationToken));
    }

    /// <summary>
    /// Minimal <see cref="HttpMessageHandler"/> that returns a canned response,
    /// with optional simulated delay that respects cancellation.
    /// </summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response, TimeSpan simulatedDelay = default)
        {
            _response = response;
            _delay = simulatedDelay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            return _response;
        }
    }
}

